    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); if *zl <= *zr { $crate::apcrl_log::zapcrl_emit_fatal(file!(), line!(), &format!("{}: {} ({:?}) <= {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } }};
}
#[macro_export] macro_rules! apcrl_fatal_ge {
    ($left:expr, $right:expr, $($arg:tt)*) => {{ let (zl, zr) = (&$left, &$right); if *zl >= *zr { $crate::apcrl_log::zapcrl_emit_fatal(file!(), line!(), &format!("{}: {} ({:?}) >= {} ({:?})", format!($($arg)*), stringify!($left), zl, stringify!($right), zr)); } }};
}

