//! Logging infrastructure — severity-named macros with auto file/line capture.
//!
//! All application logging goes through `apcrl_*_now!`, `apcrl_*_if!`, and
//! comparison variants. No naked `println!`/`eprintln!` elsewhere in the codebase.
//!
//! Output is line-oriented to stdout. Format:
//!   `[LEVEL] [file:line] message`
//!
//! Suffix families:
//!   `_now`  — unconditional emission
//!   `_if`   — boolean conditional, returns the bool
//!   `_eq`, `_ne`, `_lt`, `_gt`, `_le`, `_ge` — comparison conditional,
//!            stringifies arguments, returns the bool

pub const APCRL_LEVEL_TRACE: &str = "[TRACE]";
pub const APCRL_LEVEL_INFO:  &str = "[INFO]";
pub const APCRL_LEVEL_ERROR: &str = "[ERROR]";
pub const APCRL_LEVEL_FATAL: &str = "[FATAL]";

/// Macro infrastructure — do not call directly.
#[doc(hidden)]
pub fn zapcrl_emit(level: &str, file: &str, line: u32, msg: &str) {
    println!("{} [{}:{}] {}", level, file, line, msg);
}

/// Macro infrastructure — do not call directly.
#[doc(hidden)]
pub fn zapcrl_emit_fatal(file: &str, line: u32, msg: &str) -> ! {
    println!("{} [{}:{}] {}", APCRL_LEVEL_FATAL, file, line, msg);
    std::process::exit(1);
}

// ============================================================
// Unconditional (_now)
// ============================================================

#[macro_export]
macro_rules! apcrl_trace_now {
    ($($arg:tt)*) => {
        $crate::apcrl_log::zapcrl_emit(
            $crate::apcrl_log::APCRL_LEVEL_TRACE,
            file!(), line!(), &format!($($arg)*))
    };
}

#[macro_export]
macro_rules! apcrl_info_now {
    ($($arg:tt)*) => {
        $crate::apcrl_log::zapcrl_emit(
            $crate::apcrl_log::APCRL_LEVEL_INFO,
            file!(), line!(), &format!($($arg)*))
    };
}

#[macro_export]
macro_rules! apcrl_error_now {
    ($($arg:tt)*) => {
        $crate::apcrl_log::zapcrl_emit(
            $crate::apcrl_log::APCRL_LEVEL_ERROR,
            file!(), line!(), &format!($($arg)*))
    };
}

#[macro_export]
macro_rules! apcrl_fatal_now {
    ($($arg:tt)*) => {
        $crate::apcrl_log::zapcrl_emit_fatal(
            file!(), line!(), &format!($($arg)*))
    };
}

// ============================================================
// Boolean conditional (_if) — returns the bool
// ============================================================

#[macro_export]
macro_rules! apcrl_trace_if {
    ($cond:expr, $($arg:tt)*) => {{
        let z_cond = $cond;
        if z_cond {
            $crate::apcrl_log::zapcrl_emit(
                $crate::apcrl_log::APCRL_LEVEL_TRACE,
                file!(), line!(), &format!($($arg)*));
        }
        z_cond
    }};
}

#[macro_export]
macro_rules! apcrl_error_if {
    ($cond:expr, $($arg:tt)*) => {{
        let z_cond = $cond;
        if z_cond {
            $crate::apcrl_log::zapcrl_emit(
                $crate::apcrl_log::APCRL_LEVEL_ERROR,
                file!(), line!(), &format!($($arg)*));
        }
        z_cond
    }};
}

#[macro_export]
macro_rules! apcrl_fatal_if {
    ($cond:expr, $($arg:tt)*) => {
        if $cond {
            $crate::apcrl_log::zapcrl_emit_fatal(
                file!(), line!(), &format!($($arg)*));
        }
    };
}

// ============================================================
// Comparison conditional — stringifies arguments, returns bool
// ============================================================

macro_rules! zapcrl_define_cmp {
    ($name:ident, $level:expr, $op:tt, $op_str:expr) => {
        #[macro_export]
        macro_rules! $name {
            ($left:expr, $right:expr, $$($arg:tt)*) => {{
                let z_left = &$left;
                let z_right = &$right;
                let z_cond = *z_left $op *z_right;
                if z_cond {
                    $crate::apcrl_log::zapcrl_emit(
                        $level,
                        file!(), line!(),
                        &format!("{}: {} ({:?}) {} {} ({:?})",
                            format!($$($arg)*),
                            stringify!($left), z_left,
                            $op_str,
                            stringify!($right), z_right));
                }
                z_cond
            }};
        }
    };
}

macro_rules! zapcrl_define_cmp_fatal {
    ($name:ident, $op:tt, $op_str:expr) => {
        #[macro_export]
        macro_rules! $name {
            ($left:expr, $right:expr, $$($arg:tt)*) => {
                let z_left = &$left;
                let z_right = &$right;
                if *z_left $op *z_right {
                    $crate::apcrl_log::zapcrl_emit_fatal(
                        file!(), line!(),
                        &format!("{}: {} ({:?}) {} {} ({:?})",
                            format!($$($arg)*),
                            stringify!($left), z_left,
                            $op_str,
                            stringify!($right), z_right));
                }
            };
        }
    };
}

// trace comparison variants
zapcrl_define_cmp!(apcrl_trace_eq, $crate::apcrl_log::APCRL_LEVEL_TRACE, ==, "==");
zapcrl_define_cmp!(apcrl_trace_ne, $crate::apcrl_log::APCRL_LEVEL_TRACE, !=, "!=");
zapcrl_define_cmp!(apcrl_trace_lt, $crate::apcrl_log::APCRL_LEVEL_TRACE, <,  "<");
zapcrl_define_cmp!(apcrl_trace_gt, $crate::apcrl_log::APCRL_LEVEL_TRACE, >,  ">");
zapcrl_define_cmp!(apcrl_trace_le, $crate::apcrl_log::APCRL_LEVEL_TRACE, <=, "<=");
zapcrl_define_cmp!(apcrl_trace_ge, $crate::apcrl_log::APCRL_LEVEL_TRACE, >=, ">=");

// error comparison variants
zapcrl_define_cmp!(apcrl_error_eq, $crate::apcrl_log::APCRL_LEVEL_ERROR, ==, "==");
zapcrl_define_cmp!(apcrl_error_ne, $crate::apcrl_log::APCRL_LEVEL_ERROR, !=, "!=");
zapcrl_define_cmp!(apcrl_error_lt, $crate::apcrl_log::APCRL_LEVEL_ERROR, <,  "<");
zapcrl_define_cmp!(apcrl_error_gt, $crate::apcrl_log::APCRL_LEVEL_ERROR, >,  ">");
zapcrl_define_cmp!(apcrl_error_le, $crate::apcrl_log::APCRL_LEVEL_ERROR, <=, "<=");
zapcrl_define_cmp!(apcrl_error_ge, $crate::apcrl_log::APCRL_LEVEL_ERROR, >=, ">=");

// fatal comparison variants
zapcrl_define_cmp_fatal!(apcrl_fatal_eq, ==, "==");
zapcrl_define_cmp_fatal!(apcrl_fatal_ne, !=, "!=");
zapcrl_define_cmp_fatal!(apcrl_fatal_lt, <,  "<");
zapcrl_define_cmp_fatal!(apcrl_fatal_gt, >,  ">");
zapcrl_define_cmp_fatal!(apcrl_fatal_le, <=, "<=");
zapcrl_define_cmp_fatal!(apcrl_fatal_ge, >=, ">=");

